import math
from collections import defaultdict

n = input().strip()
s = n
digit_counts = defaultdict(int)
for c in s:
    digit_counts[c] += 1

unique_digits = list(digit_counts.keys())
total = 0

def backtrack(current_counts, used_zero):
    global total
    if sum(current_counts.values()) == 0:
        return
    for digit in unique_digits:
        if current_counts[digit] > 0:
            new_counts = current_counts.copy()
            new_counts[digit] -= 1
            if new_counts[digit] == 0:
                del new_counts[digit]
            if digit == '0' and not used_zero:
                backtrack(new_counts, used_zero)
            else:
                if digit != '0' or used_zero:
                    length = sum(new_counts.values()) + 1
                    numerator = math.factorial(length - 1)
                    denominator = 1
                    for cnt in new_counts.values():
                        denominator *= math.factorial(cnt)
                    if digit == '0':
                        numerator_zero = math.factorial(length - 1)
                        denominator_zero = 1
                        for cnt in new_counts.values():
                            denominator_zero *= math.factorial(cnt)
                        total += numerator_zero // denominator_zero
                    else:
                        total += numerator // denominator
                backtrack(new_counts, True)

initial_counts = digit_counts.copy()
backtrack(initial_counts, False)
print(total)
